// Build a tiled, rotated, FAINT watermark SVG sized to the given image.
// Text tilts top-left -> bottom-right (rotate -35). Opacity 0.30 = faint.
export function buildWatermarkSvg(width: number, height: number): Buffer {
  const fontSize = Math.max(14, Math.round(Math.min(width, height) / 30))
  const scale = fontSize / WM_REF
  const textWidth = WM_ADVANCE * scale
  const gap = fontSize * 5.5             // vertical spacing between rows
  const stepX = textWidth + fontSize * 6 // horizontal spacing between instances
  const extra = Math.max(width, height)

  const uses: string[] = []
  for (let y = -extra; y < height + extra; y += gap) {
    for (let x = -extra; x < width + extra; x += stepX) {
      uses.push(`<use xlink:href="#wm" transform="translate(${x.toFixed(1)} ${y.toFixed(1)}) scale(${scale.toFixed(4)})"/>`)
    }
  }

  return Buffer.from(
    `<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">` +
    `<defs><path id="wm" d="${WM_PATH_D}" fill="#FFFFFF" fill-opacity="0.30"/></defs>` +
    `<g transform="rotate(-35 ${width / 2} ${height / 2})">${uses.join("")}</g>` +
    `</svg>`
  )
}
